solution: class Solution {
public:
    vector<int> gardenNoAdj(int n, vector<vector<int>>& paths) {
        vector<vector<int>> adj(n + 1);
        for (const auto& p : paths) {
            adj[p[0]].push_back(p[1]);
            adj[p[1]].push_back(p[0]);
        }
        vector<int> res(n);
        for (int i = 1; i <= n; ++i) {
            bool used[5] = {};
            for (int v : adj[i]) {
                if (res[v - 1]) used[res[v - 1]] = true;
            }
            for (int c = 1; c <= 4; ++c) {
                if (!used[c]) {
                    res[i - 1] = c;
                    break;
                }
            }
        }
        return res;
    }
};
